import sqlite3import psycopg2import os# Local SQLitelocal_conn = sqlite3.connect('db.sqlite3')local_cursor = local_conn.cursor()# Render PostgreSQLrender_conn = psycopg2.connect(os.getenv('DATABASE_URL'))render_cursor = render_conn.cursor()# Clear existing phonesrender_cursor.execute("DELETE FROM store_phone;")# Get phones from locallocal_cursor.execute("SELECT name, category_id, price, description, image, created_at FROM store_phone")phones = local_cursor.fetchall()# Insert into Renderfor phone in phones:    render_cursor.execute("""        INSERT INTO store_phone (name, category_id, price, description, image, created_at)        VALUES (%s, %s, %s, %s, %s, %s)    """, phone)render_conn.commit()print("✅ Phones transferred successfully!")local_conn.close()render_conn.close()